import { type ChangeEvent, type DragEvent, type FormEvent, useEffect, useRef, useState } from 'react'
import { Link, useNavigate, useParams } from 'react-router-dom'
import { WorkspaceCard } from '../../shared/workspace/WorkspaceCard'
import { WorkspaceHeader } from '../../shared/workspace/WorkspaceHeader'
import { WorkspaceSection } from '../../shared/workspace/WorkspaceSection'
import { useOs } from '../../../core/os/useOs'
import { upsertBoqItem, upsertSiteReport, upsertTask, type ProjectWorkspaceRepository } from '../../../core/projectWorkspace/repository'
import { getAssetRelationshipLabel, getAssetRelationships, getAssetsForEntity, getBoqBaseAmount, getBoqRevisedAmount, getBoqVariance, getBudgetByWorkSection, getCostSummary, getProjectEvents, getProjectIntelligence, getTasksInRange } from '../../../core/projectWorkspace/selectors'
import type { AssetCategory, AssetRelationship, BOQItem, PersistedProjectWorkspace, ProjectAsset, ProjectTask, ProjectWorkspaceData, SiteReport } from '../../../core/projectWorkspace/types'
import { normalizeProjectWorkspace } from '../../../core/projectWorkspace/migration'
import { useProjectWorkspace } from '../../../core/projectWorkspace/useProjectWorkspace'
import './ProjectWorkspace.css'

type SectionKey = 'overview' | 'timeline' | 'tasks' | 'schedule' | 'site' | 'files' | 'boq'
type AddKind = 'task' | 'boq' | 'site-report' | 'file' | 'photo'
const sections: Array<{ key: SectionKey; label: string }> = [
  { key: 'overview', label: 'Overview' }, { key: 'timeline', label: 'Timeline' }, { key: 'tasks', label: 'Tasks' }, { key: 'schedule', label: 'Schedule' }, { key: 'site', label: 'Site' }, { key: 'files', label: 'Files & Media' }, { key: 'boq', label: 'BOQ & Cost' },
]
const categories: AssetCategory[] = ['site-photo', 'approved-render', 'sketch-markup', 'construction-drawing', 'shop-drawing', 'material-sample', 'quotation', 'boq', 'invoice-payment', 'equipment-specification', 'meeting-document', 'handover-document']
const statusTone = (value: string) => ['blocked', 'critical', 'high', 'rejected', 'overdue'].includes(value) ? 'danger' : ['pending', 'medium', 'review', 'in-progress', 'quoting'].includes(value) ? 'warning' : ['done', 'approved', 'complete', 'installed', 'submitted'].includes(value) ? 'success' : 'neutral'
const money = (value: number) => new Intl.NumberFormat('en-US', { style: 'currency', currency: 'THB', maximumFractionDigits: 0 }).format(value)
const shortDate = (value?: string) => value ? new Date(`${value.slice(0, 10)}T00:00:00`).toLocaleDateString('en-GB', { day: '2-digit', month: 'short' }) : '—'
const uid = (prefix: string) => `${prefix}-${typeof crypto !== 'undefined' && 'randomUUID' in crypto ? crypto.randomUUID() : Date.now()}`
const nowIso = () => new Date().toISOString()
const todayIso = () => nowIso().slice(0, 10)
const addDays = (date: string, days: number) => new Date(new Date(`${date}T00:00:00.000Z`).getTime() + days * 86_400_000).toISOString().slice(0, 10)

export const ProjectWorkspace = () => {
  const { projectId = '', workspaceSection } = useParams<{ projectId: string; workspaceSection?: string }>()
  const navigate = useNavigate()
  const { data: osData } = useOs()
  const requestedSection = workspaceSection
  const activeSection = (sections.some((item) => item.key === requestedSection) ? requestedSection : 'overview') as SectionKey
  const { data: workspace, status, error, retry, repository, projectId: canonicalProjectId } = useProjectWorkspace(projectId, osData)
  const [addKind, setAddKind] = useState<AddKind | null>(null)
  const [selectedTaskId, setSelectedTaskId] = useState<string | null>(null)
  const [selectedAssetId, setSelectedAssetId] = useState<string | null>(null)
  const [selectedBoqId, setSelectedBoqId] = useState<string | null>(null)
  const activeNavRef = useRef<HTMLButtonElement>(null)

  useEffect(() => activeNavRef.current?.scrollIntoView({ block: 'nearest', inline: 'center' }), [activeSection])
  const update = (next: ProjectWorkspaceData) => repository.save(normalizeProjectWorkspace(next, canonicalProjectId))
  const openSection = (section: SectionKey) => navigate(section === 'overview' ? `/os/studio/projects/${projectId}` : `/os/studio/projects/${projectId}/${section}`)

  if (status === 'loading' && !workspace) return <ProjectLoading />
  if (error && !workspace) return <ProjectError message={error.message} onRetry={() => void retry()} />
  if (!workspace) return <MissingProject projectId={projectId} />
  const intelligence = getProjectIntelligence(workspace)

  return (
    <main className="project-workspace" id="project-workspace-main">
      {error && <div className="project-error-banner" role="alert"><span>{error.message}</span><button type="button" onClick={() => void retry()}>Retry</button></div>}
      <header className="project-workspace-header">
        <div className="project-workspace-identity">
          <Link to="/os/studio/projects" className="project-workspace-back">Studio / Projects</Link>
          <p className="project-workspace-code">{workspace.project.code}</p>
          <h1>{workspace.project.name}</h1>
          <p>{workspace.project.client} · {workspace.project.locationLabel}</p>
        </div>
        <div className="project-workspace-header-actions">
          <Status label={workspace.project.status} />
          <button className="project-workspace-add" type="button" onClick={() => setAddKind('task')}>+ Add</button>
        </div>
      </header>

      <nav className="project-workspace-nav" aria-label="Project workspace">
        {sections.map((section) => <button key={section.key} ref={activeSection === section.key ? activeNavRef : undefined} className={activeSection === section.key ? 'is-active' : ''} type="button" onClick={() => openSection(section.key)}>{section.label}</button>)}
      </nav>

      <div className="project-workspace-layout">
        <section className="project-workspace-content">
          {activeSection === 'overview' && <Overview data={workspace} intelligence={intelligence} onNavigate={openSection} onSelectAsset={setSelectedAssetId} />}
          {activeSection === 'timeline' && <Timeline data={workspace} />}
          {activeSection === 'tasks' && <Tasks data={workspace} onAdd={() => setAddKind('task')} onSelect={setSelectedTaskId} />}
          {activeSection === 'schedule' && <Schedule data={workspace} onSelect={setSelectedTaskId} />}
          {activeSection === 'site' && <Site data={workspace} onAdd={() => setAddKind('site-report')} onSelectAsset={setSelectedAssetId} />}
          {activeSection === 'files' && <Files data={workspace} onAdd={() => setAddKind('file')} onSelect={setSelectedAssetId} />}
          {activeSection === 'boq' && <Boq data={workspace} onAdd={() => setAddKind('boq')} onSelect={setSelectedBoqId} />}
        </section>
        <IntelligenceRail data={workspace} intelligence={intelligence} onNavigate={openSection} />
      </div>

      {addKind && <AddDialog initialKind={addKind} data={workspace} repository={repository} onClose={() => setAddKind(null)} onSave={async (next) => { await update(next); setAddKind(null) }} />}
      {selectedTaskId && <TaskDetail data={workspace} taskId={selectedTaskId} onClose={() => setSelectedTaskId(null)} onSave={async (task) => { await repository.upsertTask(canonicalProjectId, task) }} />}
      {selectedAssetId && <AssetDetail data={workspace} assetId={selectedAssetId} repository={repository} onClose={() => setSelectedAssetId(null)} />}
      {selectedBoqId && <BoqDetail data={workspace} itemId={selectedBoqId} onClose={() => setSelectedBoqId(null)} />}
    </main>
  )
}

const MissingProject = ({ projectId }: { projectId: string }) => (
  <main className="project-workspace project-workspace-empty"><p className="project-workspace-code">PROJECT NOT FOUND</p><h1>No workspace for “{projectId}”</h1><p>The legacy adapter could not find this project. Return to Studio and select an available project.</p><Link className="project-workspace-add" to="/os/studio/projects">Back to Studio</Link></main>
)

const ProjectLoading = () => <main className="project-workspace project-workspace-empty" aria-busy="true"><p className="project-workspace-code">LOADING PROJECT</p><h1>Hydrating workspace…</h1><p>Reading the shared project repository and local asset index.</p></main>
const ProjectError = ({ message, onRetry }: { message: string; onRetry: () => void }) => <main className="project-workspace project-workspace-empty" role="alert"><p className="project-workspace-code">PROJECT LOAD FAILED</p><h1>Last valid data was preserved</h1><p>{message}</p><button className="project-workspace-add" type="button" onClick={onRetry}>Retry hydration</button></main>

const Overview = ({ data, intelligence, onNavigate, onSelectAsset }: { data: ProjectWorkspaceData; intelligence: ReturnType<typeof getProjectIntelligence>; onNavigate: (section: SectionKey) => void; onSelectAsset: (id: string) => void }) => {
  const progressGap = data.project.actualProgress - data.project.plannedProgress
  const latestAssets = [...data.assets].filter((asset) => asset.mimeType.startsWith('image/')).sort((a, b) => b.updatedAt.localeCompare(a.updatedAt)).slice(0, 3)
  return <div className="project-workspace-stack">
    <section className="project-command-surface">
      <div><p className="project-workspace-kicker">Where the project is now</p><h2>{data.project.phase}</h2><p>{data.project.summary}</p></div>
      <div className="project-progress-block"><div><strong>{data.project.actualProgress}%</strong><span>actual progress</span></div><div className="project-progress-track"><span style={{ width: `${data.project.actualProgress}%` }} /></div><p>{Math.abs(progressGap)} points {progressGap < 0 ? 'behind' : 'ahead of'} the {data.project.plannedProgress}% plan</p></div>
    </section>
    <div className="project-metric-strip">
      <Metric label="Late / blocked" value={intelligence.lateTasks.length + intelligence.atRiskTasks.filter((task) => task.status === 'blocked').length} tone="danger" onClick={() => onNavigate('tasks')} />
      <Metric label="Pending decisions" value={intelligence.pendingDecisions.length} tone="warning" onClick={() => onNavigate('timeline')} />
      <Metric label="Open risks" value={intelligence.openRisks.length} tone="danger" onClick={() => onNavigate('overview')} />
      <Metric label="Files awaiting approval" value={intelligence.unapprovedAssets.length} tone="warning" onClick={() => onNavigate('files')} />
      <Metric label="Forecast final cost" value={money(intelligence.cost.forecastFinalCost)} onClick={() => onNavigate('boq')} />
    </div>
    <div className="project-overview-grid">
      <WorkspaceSection variant="plain" header={<WorkspaceHeader label="Today and this week" title="Delivery queue" endSlot={<button className="project-text-button" type="button" onClick={() => onNavigate('schedule')}>Open schedule</button>} />}>
        <div className="project-list">{intelligence.thisWeekTasks.map((task) => <DataRow key={task.id} title={task.title} meta={`${shortDate(task.plannedStart)}–${shortDate(task.plannedFinish)} · ${task.progress}%`} status={task.status} />)}{!intelligence.thisWeekTasks.length && <Empty title="No work scheduled" body="Add a task to build the weekly lookahead." />}</div>
      </WorkspaceSection>
      <WorkspaceSection variant="plain" header={<WorkspaceHeader label="Intervention" title="Decisions and risk" />}>
        <div className="project-list">{intelligence.pendingDecisions.map((decision) => <DataRow key={decision.id} title={decision.title} meta={`Owner ${decision.owner} · due ${shortDate(decision.dueDate)}`} status={decision.impact} />)}{intelligence.openRisks.map((risk) => <DataRow key={risk.id} title={risk.title} meta={risk.description} status={risk.severity} />)}</div>
      </WorkspaceSection>
    </div>
    <div className="project-overview-grid">
      <WorkspaceCard variant="tinted" className="project-budget-block"><p className="project-workspace-kicker">Commercial position</p><h3>{money(data.project.approvedBudget)} approved budget</h3><dl><div><dt>Revised BOQ</dt><dd>{money(intelligence.cost.revisedAmount)}</dd></div><div><dt>Actual cost recorded</dt><dd>{money(intelligence.cost.actualCost)}</dd></div><div><dt>Forecast variance</dt><dd className={intelligence.cost.varianceToBudget < 0 ? 'project-danger-text' : ''}>{money(intelligence.cost.varianceToBudget)}</dd></div></dl></WorkspaceCard>
      <WorkspaceCard variant="tinted"><p className="project-workspace-kicker">Next milestone</p><h3>{intelligence.nextMilestone?.title ?? 'No milestone planned'}</h3><p className="project-muted">{intelligence.nextMilestone ? `${shortDate(intelligence.nextMilestone.plannedFinish)} · ${intelligence.nextMilestone.status}` : 'Add the next project milestone.'}</p><p className="project-workspace-kicker project-space-top">Latest site report</p><p>{intelligence.latestSiteReport?.completedToday ?? 'No report submitted.'}</p></WorkspaceCard>
    </div>
    <WorkspaceSection variant="plain" header={<WorkspaceHeader label="Latest evidence" title="Site activity and project media" endSlot={<button className="project-text-button" type="button" onClick={() => onNavigate('files')}>View library</button>} />}><div className="project-asset-grid">{latestAssets.map((asset) => <AssetTile key={asset.id} asset={asset} data={data} onClick={() => onSelectAsset(asset.id)} />)}</div></WorkspaceSection>
  </div>
}

const Timeline = ({ data }: { data: ProjectWorkspaceData }) => <WorkspaceSection variant="plain" header={<WorkspaceHeader label="Derived from project records" title="Project timeline" endSlot={<span className="project-count">{getProjectEvents(data).length} events</span>} />}><div className="project-timeline">{getProjectEvents(data).map((event) => <article key={event.id}><time>{new Date(event.occurredAt).toLocaleDateString('en-GB', { day: '2-digit', month: 'short', year: 'numeric' })}</time><span className={`project-event-dot is-${statusTone(event.type)}`} /><div><p className="project-workspace-code">{event.entityType} / {event.actor}</p><h3>{event.title}</h3>{event.detail && <p>{event.detail}</p>}</div></article>)}</div></WorkspaceSection>

const Tasks = ({ data, onAdd, onSelect }: { data: ProjectWorkspaceData; onAdd: () => void; onSelect: (id: string) => void }) => {
  const [view, setView] = useState<'list' | 'kanban'>('list')
  return <div className="project-workspace-stack"><SectionTitle kicker="One source for task and schedule" title="Tasks" action="Add task" onAction={onAdd} /><ViewToggle value={view} options={[['list', 'List'], ['kanban', 'Kanban']]} onChange={(value) => setView(value as typeof view)} />
    {view === 'list' ? <div className="project-table-wrap"><table className="project-table"><thead><tr><th>Task</th><th>Work section</th><th>Owner</th><th>Dates</th><th>Progress</th><th>Status</th></tr></thead><tbody>{data.tasks.map((task) => <tr key={task.id} onClick={() => onSelect(task.id)}><td><strong>{task.title}</strong><span>{task.description}</span></td><td>{data.project.workSections.find((section) => section.id === task.workSectionId)?.name ?? '—'}</td><td>{data.project.members.find((member) => member.id === task.responsibleMemberId)?.name ?? task.contractor ?? 'Unassigned'}</td><td>{shortDate(task.plannedStart)}–{shortDate(task.plannedFinish)}</td><td><Progress value={task.progress} /></td><td><Status label={task.status} /></td></tr>)}</tbody></table></div> : <div className="project-kanban">{(['ready', 'in-progress', 'blocked', 'review', 'done'] as ProjectTask['status'][]).map((status) => <section key={status}><h3>{status}<span>{data.tasks.filter((task) => task.status === status).length}</span></h3>{data.tasks.filter((task) => task.status === status).map((task) => <button key={task.id} type="button" onClick={() => onSelect(task.id)}><strong>{task.title}</strong><span>{task.contractor ?? task.phase}</span><Progress value={task.progress} /></button>)}</section>)}</div>}
  </div>
}

const Schedule = ({ data, onSelect }: { data: ProjectWorkspaceData; onSelect: (id: string) => void }) => {
  const [view, setView] = useState<'timeline' | 'lookahead' | 'daily'>('timeline')
  const today = todayIso()
  const startDate = [data.project.startDate, ...data.tasks.map((task) => task.plannedStart)].sort()[0] ?? today
  const endDate = [data.project.targetHandoverDate, ...data.tasks.map((task) => task.plannedFinish)].sort().at(-1) ?? addDays(today, 28)
  const start = new Date(`${startDate}T00:00:00`); const end = new Date(`${endDate}T00:00:00`); const total = Math.max(1, end.getTime() - start.getTime())
  const position = (date: string) => Math.max(0, Math.min(100, ((new Date(`${date}T00:00:00`).getTime() - start.getTime()) / total) * 100))
  const lookahead = getTasksInRange(data.tasks, today, addDays(today, 13))
  return <div className="project-workspace-stack"><SectionTitle kicker="Shared task dates" title="Schedule" /><ViewToggle value={view} options={[['timeline', 'Timeline'], ['lookahead', '2-week lookahead'], ['daily', 'Daily site plan']]} onChange={(value) => setView(value as typeof view)} />
    {view === 'timeline' && <div className="project-schedule"><div className="project-schedule-axis"><span>{shortDate(startDate)}</span><span>{shortDate(addDays(startDate, Math.round((end.getTime() - start.getTime()) / 86_400_000 / 2)))}</span><span>{shortDate(endDate)}</span></div>{data.tasks.map((task) => <button key={task.id} type="button" className="project-schedule-row" onClick={() => onSelect(task.id)}><span>{task.title}<small>{task.status}</small></span><span className="project-schedule-track"><i className={`is-${statusTone(task.status)}`} style={{ left: `${position(task.plannedStart)}%`, width: `${Math.max(3, position(task.plannedFinish) - position(task.plannedStart))}%` }} /></span></button>)}</div>}
    {view === 'lookahead' && <div className="project-list">{lookahead.map((task) => <DataRow key={task.id} title={task.title} meta={`${shortDate(task.plannedStart)}–${shortDate(task.plannedFinish)} · ${task.contractor ?? task.phase}`} status={task.status} />)}</div>}
    {view === 'daily' && <DailyPlan data={data} startDate={today} />}
  </div>
}

const DailyPlan = ({ data, startDate }: { data: ProjectWorkspaceData; startDate: string }) => <div className="project-daily-plan">{[0, 1, 2].map((offset) => addDays(startDate, offset)).map((date) => <section key={date}><time>{new Date(`${date}T00:00:00`).toLocaleDateString('en-GB', { weekday: 'short', day: '2-digit', month: 'short' })}</time>{getTasksInRange(data.tasks, date, date).map((task) => <DataRow key={task.id} title={task.title} meta={`${task.contractor ?? task.phase} · ${task.progress}%`} status={task.status} />)}{!getTasksInRange(data.tasks, date, date).length && <p className="project-muted">No planned site activity</p>}</section>)}</div>

const Site = ({ data, onAdd, onSelectAsset }: { data: ProjectWorkspaceData; onAdd: () => void; onSelectAsset: (id: string) => void }) => <div className="project-workspace-stack"><SectionTitle kicker="Daily planning and records" title="Site" action="Add site report" onAction={onAdd} />{data.siteReports.map((report) => <WorkspaceCard key={report.id} variant="tinted" className="project-site-report"><div className="project-site-report-head"><div><p className="project-workspace-code">{report.date} / {report.shift}</p><h2>{report.workScope}</h2></div><Status label={report.status} /></div><div className="project-site-facts"><span><strong>{report.workerCount}</strong> workers</span><span><strong>{report.teams.length}</strong> teams</span><span><strong>{report.hotWork ? 'Yes' : 'No'}</strong> hot work</span><span><strong>{report.workAtHeight ? 'Yes' : 'No'}</strong> work at height</span></div><div className="project-overview-grid"><div><h3>Completed</h3><p>{report.completedToday}</p><h3>Issues</h3><p>{report.issues || 'None recorded.'}</p></div><div><h3>Tomorrow</h3><p>{report.planTomorrow}</p><h3>Supervisor</h3><p>{report.supervisor}</p></div></div><div className="project-asset-grid is-compact">{getAssetsForEntity(data, 'site-report', report.id).map((asset) => <AssetTile key={asset.id} asset={asset} data={data} onClick={() => onSelectAsset(asset.id)} />)}</div></WorkspaceCard>)}{!data.siteReports.length && <Empty title="No site reports" body="Create a daily report from the unified Add menu." />}</div>

const Files = ({ data, onAdd, onSelect }: { data: ProjectWorkspaceData; onAdd: () => void; onSelect: (id: string) => void }) => {
  const [filter, setFilter] = useState('all'); const [query, setQuery] = useState('')
  const assets = data.assets.filter((asset) => (filter === 'all' || filter === 'photos' && asset.mimeType.startsWith('image/') || filter === 'documents' && !asset.mimeType.startsWith('image/') || filter === 'unlinked' && !getAssetRelationships(data, asset.id).length || asset.category === filter) && `${asset.name} ${asset.caption ?? ''}`.toLowerCase().includes(query.toLowerCase()))
  return <div className="project-workspace-stack"><SectionTitle kicker="One asset, many relationships" title="Files & Media" action="Upload files" onAction={onAdd} /><div className="project-filter-bar"><input aria-label="Search files" placeholder="Search files and captions" value={query} onChange={(event) => setQuery(event.target.value)} /><select aria-label="Filter files" value={filter} onChange={(event) => setFilter(event.target.value)}><option value="all">All files</option><option value="photos">Photos</option><option value="documents">Documents</option><option value="unlinked">Unlinked</option>{categories.map((category) => <option key={category}>{category}</option>)}</select></div><div className="project-asset-grid">{assets.map((asset) => <AssetTile key={asset.id} asset={asset} data={data} onClick={() => onSelect(asset.id)} />)}</div>{!assets.length && <Empty title="No matching files" body="Adjust the filters or upload a project asset." />}</div>
}

const Boq = ({ data, onAdd, onSelect }: { data: ProjectWorkspaceData; onAdd: () => void; onSelect: (id: string) => void }) => {
  const summary = getCostSummary(data); const sectionsData = getBudgetByWorkSection(data)
  return <div className="project-workspace-stack"><SectionTitle kicker="Connected cost control" title="BOQ & Cost" action="Add BOQ item" onAction={onAdd} /><div className="project-metric-strip"><Metric label="Approved budget" value={money(summary.approvedBudget)} /><Metric label="Revised BOQ" value={money(summary.revisedAmount)} /><Metric label="Actual cost" value={money(summary.actualCost)} /><Metric label="Forecast final" value={money(summary.forecastFinalCost)} tone={summary.varianceToBudget < 0 ? 'danger' : 'success'} /><Metric label="Variance to budget" value={money(summary.varianceToBudget)} tone={summary.varianceToBudget < 0 ? 'danger' : 'success'} /></div>
    <WorkspaceSection variant="plain" header={<WorkspaceHeader label="Cost by work section" title="Budget position" />}><div className="project-cost-sections">{sectionsData.map((row) => <div key={row.section.id}><span>{row.section.code} · {row.section.name}</span><div><i style={{ width: `${Math.min(100, row.forecast / Math.max(row.revised, 1) * 100)}%` }} /></div><strong>{money(row.forecast)}</strong><small>of {money(row.revised)}</small></div>)}</div></WorkspaceSection>
    <div className="project-table-wrap"><table className="project-table"><thead><tr><th>Code / description</th><th>Base</th><th>Variation</th><th>Revised</th><th>Actual</th><th>Forecast</th><th>Variance</th><th>State</th></tr></thead><tbody>{data.boqItems.map((item) => <tr key={item.id} onClick={() => onSelect(item.id)}><td><strong>{item.code}</strong><span>{item.description}</span></td><td>{money(getBoqBaseAmount(item))}</td><td>{money(item.variation)}</td><td>{money(getBoqRevisedAmount(item))}</td><td>{money(item.actualCost)}</td><td>{money(item.forecastCost)}</td><td>{money(getBoqVariance(item))}</td><td><Status label={item.procurementState} /></td></tr>)}</tbody></table></div>
  </div>
}

const IntelligenceRail = ({ data, intelligence, onNavigate }: { data: ProjectWorkspaceData; intelligence: ReturnType<typeof getProjectIntelligence>; onNavigate: (section: SectionKey) => void }) => <aside className="project-intelligence-rail"><p className="project-workspace-kicker">Project intelligence</p><h2>What needs attention</h2><button type="button" onClick={() => onNavigate('tasks')}><strong>{intelligence.atRiskTasks.length}</strong><span>tasks at risk</span></button><button type="button" onClick={() => onNavigate('timeline')}><strong>{intelligence.pendingDecisions.length}</strong><span>decisions pending</span></button><button type="button" onClick={() => onNavigate('files')}><strong>{intelligence.unapprovedAssets.length}</strong><span>files awaiting approval</span></button><button type="button" onClick={() => onNavigate('boq')}><strong>{intelligence.boqWithoutActualCost.length}</strong><span>cost records incomplete</span></button><div className="project-intelligence-next"><p className="project-workspace-kicker">Next inspection / milestone</p><h3>{intelligence.nextMilestone?.title ?? 'Not scheduled'}</h3><p>{shortDate(intelligence.nextMilestone?.plannedFinish)}</p></div><div className="project-intelligence-next"><p className="project-workspace-kicker">Target handover</p><h3>{shortDate(data.project.targetHandoverDate)}</h3><p>Opening {shortDate(data.project.targetOpeningDate)}</p></div></aside>

const AddDialog = ({ initialKind, data, repository, onClose, onSave }: { initialKind: AddKind; data: PersistedProjectWorkspace; repository: ProjectWorkspaceRepository; onClose: () => void; onSave: (data: ProjectWorkspaceData) => Promise<unknown> }) => {
  const ref = useRef<HTMLDialogElement>(null); const [kind, setKind] = useState(initialKind)
  useEffect(() => ref.current?.showModal(), [])
  return <dialog ref={ref} className="project-dialog" onClose={onClose}><div className="project-dialog-head"><div><p className="project-workspace-kicker">Project-level capture</p><h2>+ Add to project</h2></div><button type="button" onClick={() => ref.current?.close()} aria-label="Close">×</button></div><div className="project-add-kinds">{([['photo', 'Upload photo'], ['file', 'Upload file'], ['task', 'Add task'], ['boq', 'Add BOQ item'], ['site-report', 'Add site report']] as Array<[AddKind, string]>).map(([value, label]) => <button key={value} className={kind === value ? 'is-active' : ''} type="button" onClick={() => setKind(value)}>{label}</button>)}</div>{(kind === 'file' || kind === 'photo') && <UploadForm kind={kind} data={data} repository={repository} onComplete={onClose} />}{kind === 'task' && <TaskForm data={data} onSave={onSave} />}{kind === 'boq' && <BoqForm data={data} onSave={onSave} />}{kind === 'site-report' && <SiteReportForm data={data} onSave={onSave} />}</dialog>
}

const TaskForm = ({ data, onSave }: { data: ProjectWorkspaceData; onSave: (data: ProjectWorkspaceData) => void }) => <form className="project-form" onSubmit={(event) => { event.preventDefault(); const form = new FormData(event.currentTarget); const stamp = nowIso(); const task: ProjectTask = { id: uid('task'), projectId: data.project.id, createdAt: stamp, updatedAt: stamp, createdBy: 'Local user', source: 'local', title: String(form.get('title')), description: String(form.get('description')), phase: String(form.get('phase')), workSectionId: String(form.get('workSectionId')) || undefined, locationId: String(form.get('locationId')) || undefined, responsibleMemberId: String(form.get('responsibleMemberId')) || undefined, contractor: String(form.get('contractor')) || undefined, plannedStart: String(form.get('plannedStart')), plannedFinish: String(form.get('plannedFinish')), dependencies: [], progress: Number(form.get('progress')), priority: String(form.get('priority')) as ProjectTask['priority'], status: String(form.get('status')) as ProjectTask['status'], timeImpactDays: 0, costImpact: 0, checklist: [], commentIds: [], assetIds: [], boqItemIds: [], siteReportIds: [], decisionIds: [], drawingReferenceIds: [] }; onSave(upsertTask(data, task)) }}><Field label="Title"><input name="title" required /></Field><Field label="Description"><textarea name="description" required /></Field><div className="project-form-grid"><Field label="Phase"><input name="phase" defaultValue="Construction" required /></Field><Field label="Work section"><select name="workSectionId"><option value="">Unassigned</option>{data.project.workSections.map((item) => <option key={item.id} value={item.id}>{item.code} · {item.name}</option>)}</select></Field><Field label="Location"><select name="locationId"><option value="">Unassigned</option>{data.project.locations.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></Field><Field label="Responsible"><select name="responsibleMemberId"><option value="">Unassigned</option>{data.project.members.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></Field><Field label="Contractor"><input name="contractor" /></Field><Field label="Priority"><select name="priority" defaultValue="medium"><option>low</option><option>medium</option><option>high</option><option>critical</option></select></Field><Field label="Planned start"><input type="date" name="plannedStart" required /></Field><Field label="Planned finish"><input type="date" name="plannedFinish" required /></Field><Field label="Status"><select name="status" defaultValue="ready"><option>backlog</option><option>ready</option><option>in-progress</option><option>blocked</option><option>review</option><option>done</option></select></Field><Field label="Progress"><input type="number" name="progress" min="0" max="100" defaultValue="0" /></Field></div><Submit label="Add task" /></form>

const BoqForm = ({ data, onSave }: { data: ProjectWorkspaceData; onSave: (data: ProjectWorkspaceData) => void }) => <form className="project-form" onSubmit={(event) => { event.preventDefault(); const f = new FormData(event.currentTarget); const stamp = nowIso(); const quantity = Number(f.get('quantity')); const materialRate = Number(f.get('materialRate')); const labourRate = Number(f.get('labourRate')); const approvedAmount = quantity * (materialRate + labourRate); const item: BOQItem = { id: uid('boq'), projectId: data.project.id, createdAt: stamp, updatedAt: stamp, createdBy: 'Local user', source: 'local', code: String(f.get('code')), workSectionId: String(f.get('workSectionId')), description: String(f.get('description')), specification: String(f.get('specification')), unit: String(f.get('unit')), quantity, materialRate, labourRate, approvedAmount, variation: Number(f.get('variation')), actualCost: Number(f.get('actualCost')), forecastCost: Number(f.get('forecastCost')) || approvedAmount, supplier: String(f.get('supplier')) || undefined, drawingReferenceIds: [], taskIds: [], assetIds: [], procurementState: 'not-started', paymentState: 'not-due', installationProgress: 0, valueStatus: 'provisional' }; onSave(upsertBoqItem(data, item)) }}><div className="project-form-grid"><Field label="BOQ code"><input name="code" required /></Field><Field label="Work section"><select name="workSectionId" required>{data.project.workSections.map((item) => <option key={item.id} value={item.id}>{item.code} · {item.name}</option>)}</select></Field></div><Field label="Description"><input name="description" required /></Field><Field label="Specification"><textarea name="specification" required /></Field><div className="project-form-grid"><Field label="Unit"><input name="unit" defaultValue="lot" required /></Field><Field label="Quantity"><input name="quantity" type="number" step="0.01" defaultValue="1" required /></Field><Field label="Material rate"><input name="materialRate" type="number" defaultValue="0" required /></Field><Field label="Labour rate"><input name="labourRate" type="number" defaultValue="0" required /></Field><Field label="Variation"><input name="variation" type="number" defaultValue="0" /></Field><Field label="Actual cost"><input name="actualCost" type="number" defaultValue="0" /></Field><Field label="Forecast cost"><input name="forecastCost" type="number" defaultValue="0" /></Field><Field label="Supplier"><input name="supplier" /></Field></div><Submit label="Add BOQ item" /></form>

const SiteReportForm = ({ data, onSave }: { data: ProjectWorkspaceData; onSave: (data: ProjectWorkspaceData) => void }) => <form className="project-form" onSubmit={(event) => { event.preventDefault(); const f = new FormData(event.currentTarget); const stamp = nowIso(); const report: SiteReport = { id: uid('report'), projectId: data.project.id, createdAt: stamp, updatedAt: stamp, createdBy: 'Local user', source: 'local', date: String(f.get('date')), shift: String(f.get('shift')) as SiteReport['shift'], teams: String(f.get('teams')).split(',').map((item) => item.trim()).filter(Boolean), workerCount: Number(f.get('workerCount')), workScope: String(f.get('workScope')), locationIds: f.getAll('locationIds').map(String), materialsArriving: String(f.get('materials')).split(',').map((item) => item.trim()).filter(Boolean), equipment: String(f.get('equipment')).split(',').map((item) => item.trim()).filter(Boolean), permitRequirements: String(f.get('permits')).split(',').map((item) => item.trim()).filter(Boolean), hotWork: f.get('hotWork') === 'on', workAtHeight: f.get('workAtHeight') === 'on', supervisor: String(f.get('supervisor')), beforeAssetIds: [], duringAssetIds: [], afterAssetIds: [], completedToday: String(f.get('completedToday')), issues: String(f.get('issues')), planTomorrow: String(f.get('planTomorrow')), taskIds: f.getAll('taskIds').map(String), boqItemIds: [], assetIds: [], status: 'submitted' }; onSave(upsertSiteReport(data, report)) }}><div className="project-form-grid"><Field label="Date"><input name="date" type="date" required /></Field><Field label="Shift"><select name="shift"><option>full-day</option><option>morning</option><option>afternoon</option><option>night</option></select></Field><Field label="Supervisor"><input name="supervisor" required /></Field><Field label="Worker count"><input name="workerCount" type="number" min="0" required /></Field></div><Field label="Work scope"><textarea name="workScope" required /></Field><div className="project-form-grid"><Field label="Teams, comma separated"><input name="teams" /></Field><Field label="Materials arriving"><input name="materials" /></Field><Field label="Equipment / tools"><input name="equipment" /></Field><Field label="Permit requirements"><input name="permits" /></Field></div><Field label="Locations"><select name="locationIds" multiple>{data.project.locations.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></Field><Field label="Related tasks"><select name="taskIds" multiple>{data.tasks.map((item) => <option key={item.id} value={item.id}>{item.title}</option>)}</select></Field><div className="project-check-row"><label><input name="hotWork" type="checkbox" /> Hot work</label><label><input name="workAtHeight" type="checkbox" /> Work at height</label></div><Field label="Work completed today"><textarea name="completedToday" required /></Field><Field label="Issues encountered"><textarea name="issues" /></Field><Field label="Plan for following day"><textarea name="planTomorrow" required /></Field><Submit label="Submit site report" /></form>

const UploadForm = ({ kind, data, repository, onComplete }: { kind: 'file' | 'photo'; data: PersistedProjectWorkspace; repository: ProjectWorkspaceRepository; onComplete: () => void }) => {
  const [files, setFiles] = useState<File[]>([]); const [dragging, setDragging] = useState(false); const [saving, setSaving] = useState(false); const [failure, setFailure] = useState('')
  const addFiles = (list: FileList | null) => setFiles((current) => [...current, ...Array.from(list ?? [])])
  const drop = (event: DragEvent<HTMLDivElement>) => { event.preventDefault(); setDragging(false); addFiles(event.dataTransfer.files) }
  const submit = async (event: FormEvent<HTMLFormElement>) => {
    event.preventDefault(); if (!files.length) return; setSaving(true); setFailure(''); const f = new FormData(event.currentTarget)
    try {
      for (const file of files) {
        const stamp = nowIso(); const id = uid('asset'); const relationships: AssetRelationship[] = [{ id: uid('rel'), assetId: id, targetType: 'project', targetId: data.project.id, relation: 'attachment' }]
        const taskId = String(f.get('taskId')); const boqId = String(f.get('boqItemId')); const reportId = String(f.get('siteReportId'))
        if (taskId) relationships.push({ id: uid('rel'), assetId: id, targetType: 'task', targetId: taskId, relation: 'attachment' })
        if (boqId) relationships.push({ id: uid('rel'), assetId: id, targetType: 'boq-item', targetId: boqId, relation: 'attachment' })
        if (reportId) relationships.push({ id: uid('rel'), assetId: id, targetType: 'site-report', targetId: reportId, relation: 'attachment' })
        const asset: ProjectAsset = { id, projectId: data.project.id, createdAt: stamp, updatedAt: stamp, createdBy: 'Local user', source: 'local', name: String(f.get('name')) || file.name, fileName: file.name, mimeType: file.type || 'application/octet-stream', sizeBytes: file.size, category: String(f.get('category')) as AssetCategory, locationId: String(f.get('locationId')) || undefined, workSectionId: String(f.get('workSectionId')) || undefined, revision: String(f.get('revision')) || undefined, approvalStatus: String(f.get('approvalStatus')) as ProjectAsset['approvalStatus'], caption: String(f.get('caption')) || undefined, storage: { kind: 'indexed-db', key: '' } }
        await repository.createAsset(data.project.id, asset, file, relationships)
      }
      onComplete()
    } catch (error) {
      setFailure(error instanceof Error ? error.message : 'Upload failed. Existing project data was preserved.')
      setSaving(false)
    }
  }
  return <form className="project-form" onSubmit={submit}>{failure && <p className="project-form-error" role="alert">{failure}</p>}<div className={`project-dropzone ${dragging ? 'is-dragging' : ''}`} onDragOver={(event) => { event.preventDefault(); setDragging(true) }} onDragLeave={() => setDragging(false)} onDrop={drop}><input type="file" multiple accept={kind === 'photo' ? 'image/*' : undefined} capture={kind === 'photo' ? 'environment' : undefined} onChange={(event: ChangeEvent<HTMLInputElement>) => addFiles(event.target.files)} /><strong>Drop {kind === 'photo' ? 'photos' : 'files'} here or choose from device</strong><span>Multiple files supported. On mobile, photo capture opens the camera when available.</span></div>{files.length > 0 && <ul className="project-upload-list">{files.map((file) => <li key={`${file.name}-${file.lastModified}`}>{file.name}<span>{Math.ceil(file.size / 1024)} KB</span></li>)}</ul>}<div className="project-form-grid"><Field label="Display name"><input name="name" placeholder="Uses filename if blank" /></Field><Field label="Category"><select name="category" defaultValue={kind === 'photo' ? 'site-photo' : 'construction-drawing'}>{categories.map((category) => <option key={category}>{category}</option>)}</select></Field><Field label="Location"><select name="locationId"><option value="">Unassigned</option>{data.project.locations.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></Field><Field label="Work section"><select name="workSectionId"><option value="">Unassigned</option>{data.project.workSections.map((item) => <option key={item.id} value={item.id}>{item.name}</option>)}</select></Field><Field label="Revision"><input name="revision" /></Field><Field label="Approval status"><select name="approvalStatus" defaultValue="pending"><option>not-required</option><option>draft</option><option>pending</option><option>approved</option><option>rejected</option></select></Field><Field label="Related task"><select name="taskId"><option value="">None</option>{data.tasks.map((item) => <option key={item.id} value={item.id}>{item.title}</option>)}</select></Field><Field label="Related BOQ item"><select name="boqItemId"><option value="">None</option>{data.boqItems.map((item) => <option key={item.id} value={item.id}>{item.code} · {item.description}</option>)}</select></Field><Field label="Related site report"><select name="siteReportId"><option value="">None</option>{data.siteReports.map((item) => <option key={item.id} value={item.id}>{item.date} · {item.workScope}</option>)}</select></Field></div><Field label="Caption or note"><textarea name="caption" /></Field><Submit label={saving ? 'Saving files…' : `Upload ${files.length || ''} ${kind === 'photo' ? 'photo' : 'file'}${files.length === 1 ? '' : 's'}`} disabled={!files.length || saving} /></form>
}

const TaskDetail = ({ data, taskId, onClose, onSave }: { data: ProjectWorkspaceData; taskId: string; onClose: () => void; onSave: (task: ProjectTask) => Promise<unknown> }) => { const task = data.tasks.find((item) => item.id === taskId); const ref = useRef<HTMLDialogElement>(null); const [failure, setFailure] = useState(''); useEffect(() => ref.current?.showModal(), []); if (!task) return null; return <dialog ref={ref} className="project-dialog is-detail" onClose={onClose}><div className="project-dialog-head"><div><p className="project-workspace-kicker">Task detail</p><h2>{task.title}</h2></div><button type="button" onClick={() => ref.current?.close()}>×</button></div><p>{task.description}</p><form className="project-form" onSubmit={async (event) => { event.preventDefault(); setFailure(''); const f = new FormData(event.currentTarget); try { await onSave({ ...task, status: String(f.get('status')) as ProjectTask['status'], progress: Number(f.get('progress')), updatedAt: nowIso() }); ref.current?.close() } catch (error) { setFailure(error instanceof Error ? error.message : 'Task update failed.') } }}>{failure && <p className="project-form-error" role="alert">{failure}</p>}<div className="project-form-grid"><Field label="Status"><select name="status" defaultValue={task.status}><option>backlog</option><option>ready</option><option>in-progress</option><option>blocked</option><option>review</option><option>done</option></select></Field><Field label="Progress"><input name="progress" type="number" min="0" max="100" defaultValue={task.progress} /></Field></div><div className="project-related"><h3>Connected records</h3><p>{getAssetsForEntity(data, 'task', task.id).length} files · {task.boqItemIds.length} BOQ items · {task.siteReportIds.length} site reports · {task.dependencies.length} dependencies</p></div><Submit label="Save task changes" /></form></dialog> }

const AssetDetail = ({ data, assetId, repository, onClose }: { data: PersistedProjectWorkspace; assetId: string; repository: ProjectWorkspaceRepository; onClose: () => void }) => {
  const asset = data.assets.find((item) => item.id === assetId); const ref = useRef<HTMLDialogElement>(null); const [url, setUrl] = useState<string>(); const [failure, setFailure] = useState(''); const relationships = getAssetRelationships(data, assetId)
  useEffect(() => { ref.current?.showModal(); let createdUrl: string | undefined; if (asset?.storage.kind === 'indexed-db') void repository.getAssetBlobUrl(asset.storage.key).then((value) => { createdUrl = value; setUrl(value) }).catch(() => setFailure('The asset blob could not be read. Metadata is still available.')); return () => { if (createdUrl) URL.revokeObjectURL(createdUrl) } }, [asset?.storage.kind, asset?.storage.key, repository])
  if (!asset) return null
  const relationValue = (type: AssetRelationship['targetType']) => relationships.find((relation) => relation.targetType === type)?.targetId ?? ''
  return <dialog ref={ref} className="project-dialog is-detail" onClose={onClose}><div className="project-dialog-head"><div><p className="project-workspace-kicker">Asset metadata</p><h2>{asset.name}</h2></div><button type="button" onClick={() => ref.current?.close()}>×</button></div>{asset.mimeType.startsWith('image/') && url ? <img className="project-asset-preview" src={url} alt={asset.caption ?? asset.name} /> : <div className="project-file-preview"><strong>{asset.category}</strong><span>{asset.fileName}</span></div>}{failure && <p className="project-form-error" role="alert">{failure}</p>}<form className="project-form" onSubmit={async (event) => { event.preventDefault(); setFailure(''); const f = new FormData(event.currentTarget); const nextRelationships: AssetRelationship[] = [{ id: relationships.find((relation) => relation.targetType === 'project')?.id ?? uid('rel'), assetId, targetType: 'project', targetId: data.project.id, relation: 'attachment' }]; for (const [targetType, field] of [['task', 'taskId'], ['boq-item', 'boqItemId'], ['site-report', 'siteReportId']] as const) { const targetId = String(f.get(field)); if (targetId) nextRelationships.push({ id: relationships.find((relation) => relation.targetType === targetType && relation.targetId === targetId)?.id ?? uid('rel'), assetId, targetType, targetId, relation: 'attachment' }) } try { await repository.updateAsset(data.project.id, { ...asset, name: String(f.get('name')), category: String(f.get('category')) as AssetCategory, approvalStatus: String(f.get('approvalStatus')) as ProjectAsset['approvalStatus'], revision: String(f.get('revision')) || undefined, caption: String(f.get('caption')) || undefined, updatedAt: nowIso() }, nextRelationships); const replacement = (f.get('replacement') as File); if (replacement?.size) await repository.replaceAssetBlob(data.project.id, asset.id, replacement, replacement.name, replacement.type || 'application/octet-stream') } catch (error) { setFailure(error instanceof Error ? error.message : 'Asset update failed.') } }}><Field label="Display name"><input name="name" defaultValue={asset.name} required /></Field><div className="project-form-grid"><Field label="Category"><select name="category" defaultValue={asset.category}>{categories.map((category) => <option key={category}>{category}</option>)}</select></Field><Field label="Approval status"><select name="approvalStatus" defaultValue={asset.approvalStatus}><option>not-required</option><option>draft</option><option>pending</option><option>approved</option><option>rejected</option></select></Field><Field label="Revision"><input name="revision" defaultValue={asset.revision} /></Field><Field label="Replace file"><input name="replacement" type="file" /></Field><Field label="Related task"><select name="taskId" defaultValue={relationValue('task')}><option value="">None</option>{data.tasks.map((item) => <option key={item.id} value={item.id}>{item.title}</option>)}</select></Field><Field label="Related BOQ item"><select name="boqItemId" defaultValue={relationValue('boq-item')}><option value="">None</option>{data.boqItems.map((item) => <option key={item.id} value={item.id}>{item.code} · {item.description}</option>)}</select></Field><Field label="Related site report"><select name="siteReportId" defaultValue={relationValue('site-report')}><option value="">None</option>{data.siteReports.map((item) => <option key={item.id} value={item.id}>{item.date} · {item.workScope}</option>)}</select></Field></div><Field label="Caption or note"><textarea name="caption" defaultValue={asset.caption} /></Field><Submit label="Save asset changes" /></form><div className="project-related"><h3>Related project records</h3>{relationships.map((relation) => <p key={relation.id}>{relation.relation} · {relation.targetType} · {getAssetRelationshipLabel(data, relation.targetType, relation.targetId)}{relation.targetType !== 'project' && <button className="project-text-button" type="button" onClick={() => void repository.unlinkAsset(data.project.id, asset.id, relation.targetType, relation.targetId).catch((error: unknown) => setFailure(error instanceof Error ? error.message : 'Unlink failed.'))}>Unlink</button>}</p>)}</div><button className="project-danger-button" type="button" onClick={() => void repository.deleteAsset(data.project.id, asset.id).then(onClose).catch((error: unknown) => setFailure(error instanceof Error ? error.message : 'Delete failed.'))}>Delete asset</button></dialog>
}

const BoqDetail = ({ data, itemId, onClose }: { data: ProjectWorkspaceData; itemId: string; onClose: () => void }) => { const item = data.boqItems.find((row) => row.id === itemId); const ref = useRef<HTMLDialogElement>(null); useEffect(() => ref.current?.showModal(), []); if (!item) return null; return <dialog ref={ref} className="project-dialog is-detail" onClose={onClose}><div className="project-dialog-head"><div><p className="project-workspace-kicker">BOQ detail · {item.code}</p><h2>{item.description}</h2></div><button type="button" onClick={() => ref.current?.close()}>×</button></div><p>{item.specification}</p><dl className="project-detail-list"><div><dt>Base amount</dt><dd>{money(getBoqBaseAmount(item))}</dd></div><div><dt>Revised amount</dt><dd>{money(getBoqRevisedAmount(item))}</dd></div><div><dt>Actual cost</dt><dd>{money(item.actualCost)}</dd></div><div><dt>Forecast</dt><dd>{money(item.forecastCost)}</dd></div><div><dt>Procurement</dt><dd><Status label={item.procurementState} /></dd></div><div><dt>Payment</dt><dd><Status label={item.paymentState} /></dd></div></dl><div className="project-related"><h3>Connected records</h3><p>{item.taskIds.length} tasks · {getAssetsForEntity(data, 'boq-item', item.id).length} files · {item.drawingReferenceIds.length} drawings</p></div></dialog> }

const AssetTile = ({ asset, data, onClick }: { asset: ProjectAsset; data: ProjectWorkspaceData; onClick: () => void }) => { const relationshipCount = getAssetRelationships(data, asset.id).length; return <button className="project-asset-tile" type="button" onClick={onClick}><span className={`project-asset-visual is-${asset.mimeType.startsWith('image/') ? 'image' : 'document'}`}><b>{asset.mimeType.startsWith('image/') ? 'IMG' : asset.fileName.split('.').pop()?.toUpperCase()}</b><small>{asset.category}</small></span><span><strong>{asset.name}</strong><small>{relationshipCount} linked record{relationshipCount === 1 ? '' : 's'} · {data.project.locations.find((item) => item.id === asset.locationId)?.name ?? 'Project wide'}</small><Status label={asset.approvalStatus} /></span></button> }
const DataRow = ({ title, meta, status }: { title: string; meta: string; status: string }) => <div className="project-data-row"><div><h3>{title}</h3><p>{meta}</p></div><Status label={status} /></div>
const Status = ({ label }: { label: string }) => <span className={`project-status is-${statusTone(label)}`}>{label.replaceAll('-', ' ')}</span>
const Metric = ({ label, value, tone = 'neutral', onClick }: { label: string; value: number | string; tone?: string; onClick?: () => void }) => <button className={`project-metric is-${tone}`} type="button" onClick={onClick} disabled={!onClick}><span>{label}</span><strong>{value}</strong></button>
const Progress = ({ value }: { value: number }) => <span className="project-inline-progress"><i style={{ width: `${Math.max(0, Math.min(100, value))}%` }} /></span>
const SectionTitle = ({ kicker, title, action, onAction }: { kicker: string; title: string; action?: string; onAction?: () => void }) => <div className="project-section-title"><div><p className="project-workspace-kicker">{kicker}</p><h2>{title}</h2></div>{action && <button className="project-workspace-add" type="button" onClick={onAction}>{action}</button>}</div>
const ViewToggle = ({ value, options, onChange }: { value: string; options: Array<[string, string]>; onChange: (value: string) => void }) => <div className="project-view-toggle">{options.map(([key, label]) => <button key={key} className={value === key ? 'is-active' : ''} type="button" onClick={() => onChange(key)}>{label}</button>)}</div>
const Field = ({ label, children }: { label: string; children: React.ReactNode }) => <label className="project-field"><span>{label}</span>{children}</label>
const Submit = ({ label, disabled }: { label: string; disabled?: boolean }) => <button className="project-workspace-add project-submit" type="submit" disabled={disabled}>{label}</button>
const Empty = ({ title, body }: { title: string; body: string }) => <div className="project-empty"><h3>{title}</h3><p>{body}</p></div>
